        if (self.listen_fd >= 0) {
            try gcd.addFd(self.listen_fd, .read, cb);
        }

        // Register existing pane fds.
        for (self.sessions.items) |session| {
            for (session.windows.items) |window| {
                for (window.panes.items) |pane| {
                    if (pane.fd >= 0) {
                        gcd.addFd(pane.fd, .read, cb) catch {};
                    }
                }
            }
        }

